export const 鎮宅中央 = (bi) => {
    const u = bi.u;
    const X = (x) => x;
    const Z = (z) => z - 4;
    const 線 = (書, 寬 = 0.34) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.42) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.26 * u;
        bi.A(X(x), Z(z), r);
        c.restore();
    };
    // 米字星輪：中圈十射，射端皆圈（射線止於兩端圈緣）
    const 心 = [-1.7, 10.7];
    圈(心[0], 心[1], 0.5);
    const 端 = [
        [-1.8, 6.8], [-4.9, 7.6], [-7.2, 10.0], [-7.0, 13.2], [-4.2, 15.3],
        [-1.5, 15.8], [1.4, 15.0], [4.4, 12.8], [4.6, 9.6], [2.4, 7.5],
    ];
    for (const [tx, tz] of 端) {
        const dx = tx - 心[0], dz = tz - 心[1], L = Math.hypot(dx, dz);
        const s0 = 0.6 / L, s1 = 0.52 / L;
        線(p => p.M(X(心[0] + dx * s0), Z(心[1] + dz * s0)).L(X(tx - dx * s1), Z(tz - dz * s1)), 0.4);
        圈(tx, tz, 0.42);
    }
    // 傘蓋：圈桿（兩端圈，分段避頂圈）＋頂圈斜簷
    線(p => p.M(X(-7.0), Z(17.1)).L(X(-2.15), Z(17.02)), 0.42);
    線(p => p.M(X(-0.85), Z(17.0)).L(X(5.6), Z(16.9)), 0.42);
    圈(-7.6, 17.2);
    圈(6.2, 16.9);
    圈(-1.5, 16.6, 0.5);
    線(p => p.M(X(-1.9), Z(16.9)).L(X(-6.8), Z(18.3)), 0.42);
    線(p => p.M(X(-1.1), Z(16.9)).L(X(5.4), Z(18.1)), 0.42);
    // 左右圈柱
    for (const z of [18.6, 20.2, 21.8, 23.4, 25.0])
        圈(-7.9, z, 0.44);
    for (const z of [18.9, 20.5, 22.2, 23.8])
        圈(5.9, z, 0.44);
    // 雙塔梯身：左右各三匣（豎欄＋桁）
    const 匣 = (x0, x1, z0, z1, 桁) => {
        線(p => p.M(X(x0), Z(z0 - 0.2)).L(X(x0), Z(z1 + 0.2)));
        線(p => p.M(X(x1), Z(z0 - 0.2)).L(X(x1), Z(z1 + 0.2)));
        for (const z of [z0, ...桁, z1])
            線(p => p.M(X(x0) - 0.25, Z(z)).L(X(x1) + 0.25, Z(z)));
    };
    匣(-6.3, -2.2, 18.4, 21.2, [19.8]);
    匣(-6.4, -2.2, 22.0, 24.8, [23.4]);
    匣(-6.5, -1.9, 25.8, 31.6, [27.4, 29.0, 30.3]);
    匣(-0.9, 4.3, 18.2, 21.0, [19.6]);
    匣(-0.9, 4.4, 21.8, 24.6, [23.2]);
    匣(-0.9, 4.5, 25.6, 31.4, [27.2, 28.8, 30.1]);
    // 中縫豎
    線(p => p.M(X(-1.4), Z(18.2)).L(X(-1.4), Z(31.5)), 0.4);
    // 鬼尾三渦足（田匣承巳形渦尾）＋右長欄
    const 鬼尾 = (cx, z0) => {
        線(p => p.M(X(cx - 1.7), Z(z0)).L(X(cx + 1.7), Z(z0 - 0.1)).L(X(cx + 1.7), Z(z0 + 2.2))
            .L(X(cx - 1.7), Z(z0 + 2.3)).L(X(cx - 1.7), Z(z0)));
        線(p => p.M(X(cx - 1.6), Z(z0 + 1.1)).L(X(cx + 1.6), Z(z0 + 1.0)), 0.38);
        線(p => p.M(X(cx), Z(z0)).L(X(cx), Z(z0 + 2.2)), 0.38);
        // 巳形渦尾（下垂左捲成小渦）
        線(p => p.M(X(cx + 1.2), Z(z0 + 2.4))
            .C(X(cx + 1.4), Z(z0 + 3.4), X(cx + 0.6), Z(z0 + 4.4), X(cx - 0.6), Z(z0 + 4.6))
            .C(X(cx - 1.6), Z(z0 + 4.8), X(cx - 1.8), Z(z0 + 3.8), X(cx - 1.0), Z(z0 + 3.5))
            .C(X(cx - 0.5), Z(z0 + 3.3), X(cx - 0.2), Z(z0 + 3.7), X(cx - 0.4), Z(z0 + 4.0)), 0.45);
    };
    鬼尾(-5.0, 33.2);
    鬼尾(-0.6, 33.0);
    鬼尾(3.4, 33.4);
    // 右長欄（自塔右緣垂至符末）
    線(p => p.M(X(5.6), Z(24.6)).C(X(5.8), Z(29.0), X(5.9), Z(34.0), X(5.7), Z(38.6)), 0.45);
    // 左塔外欄下延
    線(p => p.M(X(-6.9), Z(31.8)).C(X(-7.0), Z(34.0), X(-7.0), Z(36.4), X(-6.8), Z(38.8)), 0.45);
};
